(function(w){"use strict";const ID="power";function compute(x){const base=Number(x.base),exponent=Number(x.exponent);if(!Number.isFinite(base)||!Number.isFinite(exponent))return{error:"밑과 지수에 숫자를 입력해 주세요."};if(base===0&&exponent<0)return{error:"0의 음수 지수는 계산할 수 없습니다."};if(base<0&&!Number.isInteger(exponent))return{error:"실수 범위에서는 음수 밑의 소수 지수를 계산할 수 없습니다."};const value=Math.pow(base,exponent);if(!Number.isFinite(value))return{error:"계산 결과가 너무 크거나 실수 범위를 벗어났습니다."};return{value}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label for="hm-power-base">밑</label><input id="hm-power-base" class="hm-calc-input" inputmode="decimal" placeholder="예: 2"></div><div class="hm-calc-field"><label for="hm-power-exp">지수</label><input id="hm-power-exp" class="hm-calc-input" inputmode="decimal" placeholder="예: 10"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">거듭제곱 계산</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [a,b]=root.querySelectorAll("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({base:a.value,exponent:b.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("계산 결과",api.formatNumber(r.value,12)));});reset.addEventListener("click",()=>{a.value=b.value="";api.setMessage(msg,"");api.clearResult(res);a.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
